SELECT ?governor ?governorLabel WHERE {
  wd:Q1509 p:P1344 ?statement.
  ?statement ps:P1344 ?governor.
  ?statement pq:P580 ?start.
  ?statement pq:P582 ?end.
  FILTER (year(?start) <= 1865 && year(?end) >= 1865)
  OPTIONAL { ?governor rdfs:label ?governorLabel. FILTER (lang(?governorLabel) = "en") }
}

